1203 void LowerTypeTestsModule::lowerTypeTestCalls(
1204     ArrayRef<Metadata *> TypeIds, Constant *CombinedGlobalAddr,
1205     const DenseMap<GlobalTypeMember *, uint64_t> &GlobalLayout) {
1206   // For each type identifier in this disjoint set...
1207   for (const auto &[TypeId, BSI] : buildBitSets(TypeIds, GlobalLayout)) {
1208     ByteArrayInfo *BAI = nullptr;
1209     TypeIdLowering TIL;
1210 
1211     uint64_t GlobalOffset =
1212         BSI.ByteOffset + ((BSI.BitSize - 1) << BSI.AlignLog2);
1213     TIL.OffsetedGlobal = ConstantExpr::getGetElementPtr(
1214         Int8Ty, CombinedGlobalAddr, ConstantInt::get(IntPtrTy, GlobalOffset)),
1215     TIL.AlignLog2 = ConstantInt::get(IntPtrTy, BSI.AlignLog2);
1216     TIL.SizeM1 = ConstantInt::get(IntPtrTy, BSI.BitSize - 1);
1217     if (BSI.isAllOnes()) {
1218       TIL.TheKind = (BSI.BitSize == 1) ? TypeTestResolution::Single
1219                                        : TypeTestResolution::AllOnes;
1220     } else if (BSI.BitSize <= IntPtrTy->getBitWidth()) {
1221       TIL.TheKind = TypeTestResolution::Inline;
1222       uint64_t InlineBits = 0;
1223       for (auto Bit : BSI.Bits)
1224         InlineBits |= uint64_t(1) << Bit;
1225       if (InlineBits == 0)
1226         TIL.TheKind = TypeTestResolution::Unsat;
1227       else
1228         TIL.InlineBits = ConstantInt::get(
1229             (BSI.BitSize <= 32) ? Int32Ty : Int64Ty, InlineBits);
1230     } else {
1231       TIL.TheKind = TypeTestResolution::ByteArray;
1232       ++NumByteArraysCreated;
1233       BAI = createByteArray(BSI);
1234       TIL.TheByteArray = BAI->ByteArray;
1235       TIL.BitMask = BAI->MaskGlobal;
1236     }
1237 
1238     TypeIdUserInfo &TIUI = TypeIdUsers[TypeId];
1239 
1240     if (TIUI.IsExported) {
1241       uint8_t *MaskPtr = exportTypeId(cast<MDString>(TypeId)->getString(), TIL);
1242       if (BAI)
1243         BAI->MaskPtr = MaskPtr;
1244     }
1245 
1246     // Lower each call to llvm.type.test for this type identifier.
1247     for (CallInst *CI : TIUI.CallSites) {
1248       ++NumTypeTestCallsLowered;
1249       Value *Lowered = lowerTypeTestCall(TypeId, CI, TIL);
1250       if (Lowered) {
1251         CI->replaceAllUsesWith(Lowered);
