1335 // Create an inline asm constant representing a jump table entry for the target.
1336 // This consists of an instruction sequence containing a relative branch to
1337 // Dest.
1338 InlineAsm *
1339 LowerTypeTestsModule::createJumpTableEntryAsm(Triple::ArchType JumpTableArch) {
1340   std::string Asm;
1341   raw_string_ostream AsmOS(Asm);
1342 
1343   if (JumpTableArch == Triple::x86 || JumpTableArch == Triple::x86_64) {
1344     bool Endbr = false;
1345     if (const auto *MD = mdconst::extract_or_null<ConstantInt>(
1346             M.getModuleFlag("cf-protection-branch")))
1347       Endbr = !MD->isZero();
1348     if (Endbr)
1349       AsmOS << (JumpTableArch == Triple::x86 ? "endbr32\n" : "endbr64\n");
1350     AsmOS << "jmp ${0:c}@plt\n";
1351     if (Endbr)
1352       AsmOS << ".balign 16, 0xcc\n";
1353     else
1354       AsmOS << "int3\nint3\nint3\n";
1355   } else if (JumpTableArch == Triple::arm) {
1356     AsmOS << "b $0\n";
1357   } else if (JumpTableArch == Triple::aarch64) {
1358     if (hasBranchTargetEnforcement())
1359       AsmOS << "bti c\n";
1360     AsmOS << "b $0\n";
1361   } else if (JumpTableArch == Triple::thumb) {
1362     if (!CanUseThumbBWJumpTable) {
1363       // In Armv6-M, this sequence will generate a branch without corrupting
1364       // any registers. We use two stack words; in the second, we construct the
1365       // address we'll pop into pc, and the first is used to save and restore
1366       // r0 which we use as a temporary register.
1367       //
1368       // To support position-independent use cases, the offset of the target
1369       // function is stored as a relative offset (which will expand into an
1370       // R_ARM_REL32 relocation in ELF, and presumably the equivalent in other
1371       // object file types), and added to pc after we load it. (The alternative
1372       // B.W is automatically pc-relative.)
1373       //
1374       // There are five 16-bit Thumb instructions here, so the .balign 4 adds a
1375       // sixth halfword of padding, and then the offset consumes a further 4
1376       // bytes, for a total of 16, which is very convenient since entries in
1377       // this jump table need to have power-of-two size.
1378       AsmOS << "push {r0,r1}\n"
1379             << "ldr r0, 1f\n"
1380             << "0: add r0, r0, pc\n"
1381             << "str r0, [sp, #4]\n"
1382             << "pop {r0,pc}\n"
1383             << ".balign 4\n"
1384             << "1: .word $0 - (0b + 4)\n";
1385     } else {
1386       if (hasBranchTargetEnforcement())
1387         AsmOS << "bti\n";
1388       AsmOS << "b.w $0\n";
1389     }
1390   } else if (JumpTableArch == Triple::riscv32 ||
1391              JumpTableArch == Triple::riscv64) {
1392     AsmOS << "tail $0@plt\n";
1393   } else if (JumpTableArch == Triple::loongarch64) {
1394     AsmOS << "pcalau12i $$t0, %pc_hi20($0)\n"
1395           << "jirl $$r0, $$t0, %pc_lo12($0)\n";
1396   } else {
1397     report_fatal_error("Unsupported architecture for jump tables");
1398   }
1399 
1400   return InlineAsm::get(
1401       FunctionType::get(Type::getVoidTy(M.getContext()), PtrTy, false),
1402       AsmOS.str(), "s",
1403       /*hasSideEffects=*/true);
1404 }
